from functools import lru_cache
from typing import Dict, List, Optional

try:
    import tiktoken
except ImportError:  # pragma: no cover - fallback for environments without tiktoken
    tiktoken = None


# Use a real tokenizer in production; fall back to character count only if unavailable.
@lru_cache(maxsize=1)
def _get_token_encoder():
    if tiktoken is None:
        return None

    try:
        return tiktoken.get_encoding("cl100k_base")
    except Exception:
        return None


def tokenize_len(text: str) -> int:
    encoder = _get_token_encoder()
    if encoder is None:
        return len(text)
    return len(encoder.encode(text))


def _normalize_with_index_map(text: str) -> Dict:
    """Normalize whitespace and keep mapping to original indices."""
    norm_chars: List[str] = []
    index_map: List[int] = []
    in_ws = False

    for i, ch in enumerate(text):
        if ch.isspace():
            if not in_ws:
                norm_chars.append(" ")
                index_map.append(i)
                in_ws = True
        else:
            norm_chars.append(ch)
            index_map.append(i)
            in_ws = False

    return {"text": "".join(norm_chars), "map": index_map}


def _find_best_span(text: str, anchor_text: str, cursor: int) -> Dict:
    """Find best span for anchor_text in original text.

    Tries exact match first, then relaxed whitespace-normalized match.
    """
    if not anchor_text:
        return {"start": cursor, "end": cursor}

    variants: List[str] = [anchor_text]
    if anchor_text != anchor_text.lstrip("\n"):
        variants.append(anchor_text.lstrip("\n"))
    if anchor_text != anchor_text.strip():
        variants.append(anchor_text.strip())

    seen = set()
    unique_variants: List[str] = []
    for v in variants:
        if v and v not in seen:
            unique_variants.append(v)
            seen.add(v)

    # 1) Exact match preferring positions at/after cursor.
    for v in unique_variants:
        pos = text.find(v, cursor)
        if pos >= 0:
            return {"start": pos, "end": pos + len(v)}

    # 2) Exact global match fallback.
    for v in unique_variants:
        pos = text.find(v)
        if pos >= 0:
            return {"start": pos, "end": pos + len(v)}

    # 3) Whitespace-normalized fallback.
    norm_src = _normalize_with_index_map(text)
    norm_anchor = " ".join(anchor_text.split())
    if norm_anchor:
        npos = norm_src["text"].find(norm_anchor)
        if npos >= 0:
            start = norm_src["map"][npos]
            end_norm_idx = npos + len(norm_anchor) - 1
            end = norm_src["map"][end_norm_idx] + 1
            return {"start": start, "end": end}

    # 4) Last resort: clamp to cursor with anchor length.
    start = max(0, min(cursor, len(text)))
    end = max(start, min(len(text), start + len(anchor_text)))
    return {"start": start, "end": end}

from fastapi import FastAPI, File, Form, Request, UploadFile
from fastapi.responses import HTMLResponse, JSONResponse
from fastapi.staticfiles import StaticFiles
from fastapi.templating import Jinja2Templates

from app.chunker import chunk_document

app = FastAPI(title="RAG Chunker Demo")

app.mount("/static", StaticFiles(directory="static"), name="static")
app.mount("/samples", StaticFiles(directory="sample"), name="samples")
templates = Jinja2Templates(directory="templates")


@app.get("/", response_class=HTMLResponse)
def index(request: Request):
    return templates.TemplateResponse("index.html", {"request": request})


@app.post("/api/chunk")
async def chunk_file(
    file: UploadFile = File(...),
    base_max_size: int = Form(1024),
    key_content_max_size: int = Form(1536),
    overlap: int = Form(100),
):
    if not file.filename:
        return JSONResponse({"error": "Missing filename."}, status_code=400)

    if base_max_size <= 0 or key_content_max_size <= 0 or overlap < 0:
        return JSONResponse({"error": "Invalid chunk parameters."}, status_code=400)

    raw = await file.read()
    try:
        text = raw.decode("utf-8")
    except UnicodeDecodeError:
        try:
            text = raw.decode("gbk")
        except UnicodeDecodeError:
            return JSONResponse(
                {"error": "Unsupported file encoding. Please upload UTF-8 or GBK text files."},
                status_code=400,
            )

    if not text.strip():
        return JSONResponse({"error": "The uploaded file is empty."}, status_code=400)

    data = chunk_document(
        text=text,
        base_max_size=base_max_size,
        key_content_max_size=key_content_max_size,
        overlap=overlap,
    )

    return {
        "filename": file.filename,
        "params": {
            "base_max_size": base_max_size,
            "key_content_max_size": key_content_max_size,
            "overlap": overlap,
        },
        "result": data,
    }

